import Foundation

/// Fikstury do testów importu zaszyfrowanego klucza PKCS#8 (PBES2).
/// Wygenerowane OpenSSL 3.6.2: certyfikaty self-signed + klucze prywatne
/// zaszyfrowane hasłem "TestHaslo123" (EC P-256 i RSA-2048; warianty PRF
/// SHA-256/SHA-1 i szyfru AES-256/AES-128-CBC). Klucz pasuje do certyfikatu.
enum EncryptedKeyFixtures {
    static let password = "TestHaslo123"
    static let ecCertDER = ""
    static let ecEncSHA256 = ""
    static let ecEncSHA1 = ""
    static let ecEncAES128 = ""
    static let rsaCertDER = ""
    static let rsaEncSHA256 = ""

    static func pem(_ name: String, _ base64: String) -> String {
        "-----BEGIN \(name)-----\n\(base64)\n-----END \(name)-----\n"
    }
}
